FUNCTION ModusPonens(premise1, premise2):
 // premise1 is implication P→Q
 // premise2 is P
 IF premise1.isImplication() AND premise2.equals(premise1.antecedent):
 RETURN premise1.consequent
 ELSE
 RETURN "Cannot apply Modus Ponens"

// Example: P→Q, P ⊢ Q
// Input: Implication(rain,wet), rain
// Output: wet
